/**
 * @jest-environment node
 *
 * Tests API — Parcours complets
 *
 * Couvre les scénarios "humains" de bout en bout via l'API :
 *   P1 — Inscription complète (formulaire → réponse → données en base)
 *   P2 — Dossier enfant complet (4 blocs → validation → soumission)
 *   P3 — Anti-doublon soumission (2ème envoi → 409)
 *   P4 — Upload pièce jointe (chemin nominal)
 *   P5 — Statut admin : passage validee, refusee, annulee
 *   P6 — Badge "En retard" : inscription > 7j sans dossier détecté en base
 *
 * Préconditions :
 *   - Serveur accessible sur BASE_URL
 *   - TEST_ADMIN_SESSION défini dans .env.test
 *
 * Nettoyage :
 *   Les inscriptions créées par ces tests ont pour email test-parcours@ged-test.internal
 *   DELETE FROM gd_inscriptions WHERE referent_email = 'test-parcours@ged-test.internal';
 */

import { describe, it, expect, beforeAll, afterAll } from '@jest/globals';
import * as https from 'https';
import * as http from 'http';

const BASE_URL  = (process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3000').replace(/\/$/, '');
const SUPABASE_URL  = process.env.NEXT_PUBLIC_SUPABASE_URL || '';
const SERVICE_KEY   = process.env.SUPABASE_SERVICE_ROLE_KEY || '';
const ADMIN_TOKEN   = process.env.TEST_ADMIN_SESSION || '';
const TEST_EMAIL    = 'test-parcours@ged-test.internal';

// ─── Helpers ────────────────────────────────────────────────────────────────

function request(url: string, options: { method: string; headers?: Record<string, string>; body?: string }) {
  return new Promise<{ status: number; body: any }>((resolve, reject) => {
    const parsed  = new URL(url);
    const lib     = parsed.protocol === 'https:' ? https : http;
    const bodyBuf = options.body ? Buffer.from(options.body) : undefined;
    const req     = (lib as any).request({
      hostname: parsed.hostname,
      port:     parsed.port || (parsed.protocol === 'https:' ? 443 : 80),
      path:     parsed.pathname + parsed.search,
      method:   options.method,
      headers:  {
        ...(options.headers || {}),
        ...(bodyBuf ? { 'Content-Length': String(bodyBuf.length) } : {}),
      },
    }, (res: any) => {
      let d = '';
      res.on('data', (c: any) => d += c);
      res.on('end', () => {
        try { resolve({ status: res.statusCode, body: JSON.parse(d) }); }
        catch { resolve({ status: res.statusCode, body: d }); }
      });
    });
    req.on('error', reject);
    if (bodyBuf) req.write(bodyBuf);
    req.end();
  });
}

function api(path: string, body: object, headers?: Record<string, string>) {
  return request(`${BASE_URL}${path}`, {
    method:  'POST',
    headers: { 'Content-Type': 'application/json', ...headers },
    body:    JSON.stringify(body),
  });
}

function apiPatch(path: string, body: object, headers?: Record<string, string>) {
  return request(`${BASE_URL}${path}`, {
    method:  'PATCH',
    headers: { 'Content-Type': 'application/json', ...headers },
    body:    JSON.stringify(body),
  });
}

function apiPut(path: string, body: object, headers?: Record<string, string>) {
  return request(`${BASE_URL}${path}`, {
    method:  'PUT',
    headers: { 'Content-Type': 'application/json', ...headers },
    body:    JSON.stringify(body),
  });
}

function supabaseQuery(path: string) {
  return new Promise<{ status: number; body: any }>((resolve, reject) => {
    const parsed = new URL(`${SUPABASE_URL}/rest/v1/${path}`);
    const req = https.request({
      hostname: parsed.hostname,
      port:     443,
      path:     parsed.pathname + parsed.search,
      method:   'GET',
      headers:  {
        apikey:          SERVICE_KEY,
        Authorization:   'Bearer ' + SERVICE_KEY,
      },
    }, (res: any) => {
      let d = '';
      res.on('data', (c: any) => d += c);
      res.on('end', () => {
        try { resolve({ status: res.statusCode, body: JSON.parse(d) }); }
        catch { resolve({ status: res.statusCode, body: d }); }
      });
    });
    req.on('error', reject);
    req.end();
  });
}

// ─── Setup ──────────────────────────────────────────────────────────────────

let serverReachable = false;

beforeAll(async () => {
  try {
    const r = await request(`${BASE_URL}/`, { method: 'GET' });
    serverReachable = r.status < 600;
  } catch {
    serverReachable = false;
    console.warn(`[INFO] Serveur ${BASE_URL} non joignable — tests parcours ignorés.`);
  }
}, 30000);

function skip(name: string) {
  if (!serverReachable) { console.warn(`[SKIP] ${name} — serveur non joignable`); return true; }
  return false;
}

// ─── État partagé entre tests (séquentiels) ─────────────────────────────────

let inscriptionId   = '';
let suiviToken      = '';
let dossierRef      = '';

// ─── P1 — Inscription complète ───────────────────────────────────────────────

describe('P1 — Inscription complète', () => {
  it('crée une inscription et retourne id + suivi_token + dossier_ref', async () => {
    if (skip('P1')) return;

    const res = await api('/api/inscriptions', {
      staySlug:         'mountain-and-chill',
      sessionDate:      '2026-08-02',
      cityDeparture:    'sans_transport',
      organisation:     'Structure Test Parcours',
      socialWorkerName: 'Référent Parcours',
      email:            TEST_EMAIL,
      phone:            '0600000001',
      childFirstName:   'ParcourEnfant',
      childLastName:    'Test',
      childBirthDate:   '2014-03-10',
      remarques:        '[TEST PARCOURS COMPLET — à supprimer]',
      priceTotal:       885,
      consent:          true,
      paymentMethod:    'transfer',
    });

    expect(res.status).toBe(201);
    expect(res.body).toHaveProperty('id');
    expect(res.body).toHaveProperty('suivi_token');
    expect(res.body).toHaveProperty('dossier_ref');
    expect(res.body.status).toBe('en_attente');
    expect(res.body.dossier_ref).toMatch(/^DOS-\d{8}-[A-Z0-9]{8}$/);

    // Stocker pour les tests suivants
    inscriptionId = res.body.id;
    suiviToken    = res.body.suivi_token;
    dossierRef    = res.body.dossier_ref;

    console.info(`   → Inscription créée : ${dossierRef} (${inscriptionId})`);
  });

  it('inscription visible en base via service_role', async () => {
    if (skip('P1-base') || !inscriptionId) return;

    const res = await supabaseQuery(
      `gd_inscriptions?id=eq.${inscriptionId}&select=id,status,referent_email`
    );

    expect(res.status).toBe(200);
    expect(Array.isArray(res.body)).toBe(true);
    expect(res.body).toHaveLength(1);
    expect(res.body[0].referent_email).toBe(TEST_EMAIL);
    expect(res.body[0].status).toBe('en_attente');
  });
});

// ─── P2 — Dossier enfant complet ────────────────────────────────────────────

describe('P2 — Dossier enfant : remplissage des 4 blocs', () => {
  const BLOCS = [
    {
      bloc: 'bulletin_complement',
      data: { nom_enfant: 'Test', prenom_enfant: 'Parcours', autorisation_accepte: true },
      label: 'Bulletin',
    },
    {
      bloc: 'fiche_sanitaire',
      data: { medecin_nom: 'Dr Test', autorisation_soins_accepte: true },
      label: 'Fiche sanitaire',
    },
    {
      bloc: 'fiche_liaison_jeune',
      data: { motivation: 'Test automatisé', engagement_accepte: true },
      label: 'Fiche liaison',
    },
    {
      bloc: 'fiche_renseignements',
      data: { type_situation: 'famille', contact_urgence_nom: 'Parent Test', contact_urgence_tel: '0600000002' },
      label: 'Renseignements',
    },
  ];

  for (const { bloc, data, label } of BLOCS) {
    it(`valide le bloc ${label} (completed=true)`, async () => {
      if (skip(`P2-${bloc}`) || !suiviToken) return;

      const res = await apiPatch(`/api/dossier-enfant/${inscriptionId}`, {
        token:     suiviToken,
        bloc,
        data,
        completed: true,
      });

      expect([200, 201]).toContain(res.status);
      expect(res.body).toHaveProperty(bloc + '_completed', true);
    });
  }

  it('dossier en base : 4 blocs à true après validation', async () => {
    if (skip('P2-base') || !inscriptionId) return;

    const res = await supabaseQuery(
      `gd_dossier_enfant?inscription_id=eq.${inscriptionId}` +
      `&select=bulletin_completed,sanitaire_completed,liaison_completed,renseignements_completed`
    );

    expect(res.status).toBe(200);
    expect(res.body).toHaveLength(1);
    const d = res.body[0];
    expect(d.bulletin_completed).toBe(true);
    expect(d.sanitaire_completed).toBe(true);
    expect(d.liaison_completed).toBe(true);
    expect(d.renseignements_completed).toBe(true);
  });
});

// ─── P3 — Soumission du dossier ──────────────────────────────────────────────

describe('P3 — Soumission et anti-doublon', () => {
  it('soumet le dossier complet → 200 + ged_sent_at renseigné', async () => {
    if (skip('P3-submit') || !suiviToken) return;

    const res = await api(`/api/dossier-enfant/${inscriptionId}/submit`, {
      token: suiviToken,
    });

    expect(res.status).toBe(200);
    expect(res.body).toHaveProperty('success', true);
  });

  it('2ème soumission → 409 (anti-doublon)', async () => {
    if (skip('P3-doublon') || !suiviToken) return;

    const res = await api(`/api/dossier-enfant/${inscriptionId}/submit`, {
      token: suiviToken,
    });

    expect(res.status).toBe(409);
  });

  it('ged_sent_at non null en base après soumission', async () => {
    if (skip('P3-base') || !inscriptionId) return;

    const res = await supabaseQuery(
      `gd_dossier_enfant?inscription_id=eq.${inscriptionId}&select=ged_sent_at`
    );

    expect(res.status).toBe(200);
    expect(res.body[0].ged_sent_at).not.toBeNull();
  });
});

// ─── P4 — Upload pièce jointe (chemin nominal) ──────────────────────────────

describe('P4 — Upload pièce jointe', () => {
  it('upload un PDF valide sur l\'inscription de test', async () => {
    if (skip('P4-upload')) return;

    // Utilise TEST_INSCRIPTION_ID (incomplète, non soumise) pour ne pas polluer P3
    const targetId    = process.env.TEST_INSCRIPTION_ID || inscriptionId;
    const targetToken = process.env.TEST_SUIVI_TOKEN    || suiviToken;
    if (!targetId || !targetToken) {
      console.warn('[SKIP] P4 — TEST_INSCRIPTION_ID ou TEST_SUIVI_TOKEN manquant');
      return;
    }

    // Créer un petit PDF valide (header minimal)
    const pdfContent = Buffer.from('%PDF-1.4\n1 0 obj\n<< /Type /Catalog >>\nendobj\n%%EOF');
    const boundary   = 'testboundary123';
    const body = Buffer.concat([
      Buffer.from(`--${boundary}\r\nContent-Disposition: form-data; name="token"\r\n\r\n${targetToken}\r\n`),
      Buffer.from(`--${boundary}\r\nContent-Disposition: form-data; name="type"\r\n\r\nvaccins\r\n`),
      Buffer.from(`--${boundary}\r\nContent-Disposition: form-data; name="file"; filename="test.pdf"\r\nContent-Type: application/pdf\r\n\r\n`),
      pdfContent,
      Buffer.from(`\r\n--${boundary}--\r\n`),
    ]);

    const res = await request(`${BASE_URL}/api/dossier-enfant/${targetId}/upload`, {
      method:  'POST',
      headers: { 'Content-Type': `multipart/form-data; boundary=${boundary}`, 'Content-Length': String(body.length) },
      body:    body.toString('binary'),
    });

    // 200 = uploadé, 409 = dossier déjà soumis (si TEST_INSCRIPTION_ID soumis entre-temps)
    expect([200, 409]).toContain(res.status);
    if (res.status === 200) {
      expect(res.body).toHaveProperty('storage_path');
      console.info(`   → Fichier uploadé : ${res.body.storage_path}`);
    }
  }, 15000);
});

// ─── P5 — Statut admin ───────────────────────────────────────────────────────

describe('P5 — Changement de statut admin', () => {
  it('passe l\'inscription en "validee"', async () => {
    if (skip('P5-validee') || !inscriptionId || !ADMIN_TOKEN) {
      if (!ADMIN_TOKEN) console.warn('[SKIP] P5 — TEST_ADMIN_SESSION manquant');
      return;
    }

    const res = await apiPut(`/api/admin/inscriptions/${inscriptionId}`,
      { status: 'validee' },
      { Authorization: `Bearer ${ADMIN_TOKEN}` }
    );

    expect(res.status).toBe(200);
  });

  it('passe l\'inscription en "refusee"', async () => {
    if (skip('P5-refusee') || !inscriptionId || !ADMIN_TOKEN) return;

    const res = await apiPut(`/api/admin/inscriptions/${inscriptionId}`,
      { status: 'refusee' },
      { Authorization: `Bearer ${ADMIN_TOKEN}` }
    );

    expect(res.status).toBe(200);
  });

  it('statut "refusee" persisté en base', async () => {
    if (skip('P5-base') || !inscriptionId) return;

    const res = await supabaseQuery(
      `gd_inscriptions?id=eq.${inscriptionId}&select=status`
    );

    expect(res.status).toBe(200);
    expect(res.body[0].status).toBe('refusee');
  });
});

// ─── P6 — Badge "En retard" ──────────────────────────────────────────────────

describe('P6 — Badge En retard (condition en base)', () => {
  it('détecte en base les inscriptions > 7j sans dossier soumis', async () => {
    if (skip('P6') || !SERVICE_KEY) return;

    // Calculer la date limite : il y a 8 jours
    const limit = new Date();
    limit.setDate(limit.getDate() - 8);
    const limitISO = limit.toISOString();

    const res = await supabaseQuery(
      `gd_inscriptions?select=id,created_at,referent_email` +
      `&created_at=lt.${limitISO}` +
      `&id=not.in.(select inscription_id from gd_dossier_enfant where ged_sent_at is not null)` +
      `&limit=5`
    );

    // On vérifie juste que la requête fonctionne — le nombre peut être 0
    expect(res.status).toBe(200);
    expect(Array.isArray(res.body)).toBe(true);
    console.info(`   → Inscriptions en retard détectées : ${res.body.length}`);
  });
});

// ─── Cleanup ─────────────────────────────────────────────────────────────────

afterAll(() => {
  if (inscriptionId) {
    console.info(`\n[INFO] Nettoyage — exécuter dans Supabase SQL Editor :`);
    console.info(`  DELETE FROM gd_inscriptions WHERE referent_email = '${TEST_EMAIL}';\n`);
  }
});
